-- 357_buildout_m26.sql (GENERATED) — fill empty lessons for "SIT Exam Review — Advanced Topics"
-- Module c100001a-0000-0000-0000-00000000001a. Namespaced by tag 'buildout' / created_by 'buildout:m26' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c100001a-0000-0000-0000-00000000001a' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c100001a-0000-0000-0000-00000000001a' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c100001a-0000-0000-0000-00000000001a' AND created_by='buildout:m26';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Boundary retracement follows the original surveyor''s footsteps; the goal is the location the parties accepted, not a mathematically ''perfect'' line.','Priority of calls (Texas/Stafford v. King): natural monuments > artificial monuments > calls for adjoinder > course (bearing) > distance > area/quantity, all subordinate to the writing''s intent.','Senior rights govern conflicts between adjoining deeds carved from a common grantor: the first conveyance gets its full record; the junior takes the remainder.','Excess or deficiency between found original corners is distributed by proportionate (relative) measurement, not dumped into one lot.']::text[], learning_objectives=ARRAY['Recall the senior-rights / order-of-conveyance rule and apply it to a split parcel.','Rank the priority of calls (controlling elements) used to retrace a boundary.','Distinguish original-survey retracement from a new survey and the ''footsteps'' doctrine.','Apply proportionate measurement (single and double) to distribute excess and deficiency.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='a3c8c160-0a68-4aa4-9155-4ddcd1183a53';
DELETE FROM lesson_blocks WHERE lesson_id='a3c8c160-0a68-4aa4-9155-4ddcd1183a53';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['A legal description must identify a unique parcel; metes-and-bounds (the Texas norm) traces the perimeter by bearing-distance calls from a defined POB back to closure.','Lot-and-block descriptions incorporate a recorded plat by reference; the plat supplies the dimensions and monuments.','Specific (monument) calls control over general (bearing/distance) calls when they conflict—the writing is read to carry out the parties'' intent.','A description that fails to close, omits a POB, or is patently ambiguous on its face may be void; latent ambiguities are cured with extrinsic evidence.']::text[], learning_objectives=ARRAY['Identify the major types of legal description (metes-and-bounds, lot-and-block, strip/centerline, PLSS aliquot) and when each is used.','Read a metes-and-bounds call set and recognize a proper point of beginning, closure, and monument calls.','Spot defects: ambiguous calls, missing closure, conflicting bearings vs. monuments.','Apply the rules of construction that courts use to interpret an ambiguous description.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='00e59f6c-81a9-46d7-8e06-9e98efec29a8';
DELETE FROM lesson_blocks WHERE lesson_id='00e59f6c-81a9-46d7-8e06-9e98efec29a8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['Texas titles originate from a sovereign grant (Spanish/Mexican) or a State patent, archived at the GLO, not from a federal PLSS.','The GLO holds original field notes, sketches, and patents for original land grants; the county clerk records subsequent conveyances (deeds).','Texas is a ''notice'' recording state: an unrecorded conveyance is void as to a later bona fide purchaser for value without notice.','Good retracement research follows the chain backward from the current deed to the original grant, pulling field notes and adjoiner deeds.']::text[], learning_objectives=ARRAY['Trace a Texas chain of title from sovereign grant/patent through the county deed records.','Describe the role of the General Land Office (GLO) versus the county clerk''s records.','Explain the Texas recording act (notice statute) and how recording protects a bona fide purchaser.','Locate original survey field notes, abstracts, and patents needed for retracement research.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='c3bca439-c78e-42ce-9416-f7313d08680e';
DELETE FROM lesson_blocks WHERE lesson_id='c3bca439-c78e-42ce-9416-f7313d08680e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Horizontal circular curve: T = R·tan(I/2), L = R·I(rad) = R·toRad(I), LC = 2R·sin(I/2); the PC is at PI − T along the back tangent.','Stationing is continuous along the alignment; PC = PI − T and PT = PC + L (NOT PI + T).','Equal-tangent vertical curve elevation: y = g1·x + (A/(2L))·x², where A = g2 − g1 (percent) and L is curve length in stations.','Construction stakes carry a cut/fill to design grade; slope stakes mark where the design slope meets existing ground.']::text[], learning_objectives=ARRAY['Set up and stake horizontal and vertical curves from PI, R, and design elements.','Compute curve geometry: T, L, M, E, and chord from R and I.','Compute elevations on a vertical curve and locate the high/low point.','Apply slope-staking and grade/offset stakes for construction layout.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='6c0db991-2c1f-469c-83d2-4c3eb7f8f5de';
DELETE FROM lesson_blocks WHERE lesson_id='6c0db991-2c1f-469c-83d2-4c3eb7f8f5de';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Topo deliverables are surfaces and contours; choose a method and density that resolve the smallest feature of interest.','GSD ≈ (pixel size × flight height) / focal length; smaller GSD = finer detail. For drones, GSD ≈ (sensor-pixel-pitch × H) / f.','Contours never cross or split; they V upstream at streams and point downhill on ridges; spacing shows slope (close = steep).','A DTM/DEM is bare earth; a DSM includes vegetation and structures—breaklines force the surface to honor grade changes.']::text[], learning_objectives=ARRAY['Describe topographic data-collection methods (total station, RTK GNSS, LiDAR, photogrammetry) and their accuracy regimes.','Compute photogrammetric Ground Sample Distance (GSD) from sensor and flight parameters.','Interpret contours: rules of contour behavior, interval selection, and DTM/DEM/DSM distinctions.','Plan adequate point density and breaklines for a faithful surface model.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='3a122889-17da-40cf-bf70-4e9fca9f0f31';
DELETE FROM lesson_blocks WHERE lesson_id='3a122889-17da-40cf-bf70-4e9fca9f0f31';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['The surveyor''s overriding duty is to protect the public; the legal yardstick is the standard of care of a reasonably prudent surveyor under like circumstances.','Ethics centers on competence (only practice within your expertise), independence/objectivity, confidentiality, and honesty in certifications.','Negligence requires duty, breach (falling below the standard of care), causation, and damages; standards of practice help define the duty.','A clear written contract defining scope, deliverables, and certifications is the best protection against disputes and liability.']::text[], learning_objectives=ARRAY['State the surveyor''s primary professional duty and standard of care.','Apply core ethical obligations: competence, independence, confidentiality, and honest dealing.','Explain liability theories (negligence, breach of contract) and how standards of practice define the duty.','Identify business-practice essentials: contracts, scope, certifications, and record retention.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='d9587b1a-eff4-4db8-88be-f3175623aa03';
DELETE FROM lesson_blocks WHERE lesson_id='d9587b1a-eff4-4db8-88be-f3175623aa03';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Texas surveyors are licensed under Occupations Code Ch. 1071 by TBPELS, with standards of practice in 22 TAC Ch. 138.','Credentials ladder: SIT (intern) → RPLS (boundary practice) → LSLS (original state-land boundaries, filing in the GLO).','Texas priority of calls traces to Stafford v. King; titles trace to sovereign grants/patents, not the PLSS.','Riparian boundaries shift with slow accretion/erosion but not with sudden avulsion; navigable streams follow the gradient boundary.']::text[], learning_objectives=ARRAY['Identify TBPELS, Occupations Code Ch. 1071, and 22 TAC Ch. 138 as the framework governing Texas surveyors.','Distinguish the RPLS, SIT, and LSLS credentials and their roles.','Apply key Texas boundary doctrines: priority of calls (Stafford), riparian/accretion rules, and the recording act.','Recall Texas-specific units, grant systems, and the GLO''s role in original surveys.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='beb9522e-1bab-425c-9d43-4c4d0696d9d3';
DELETE FROM lesson_blocks WHERE lesson_id='beb9522e-1bab-425c-9d43-4c4d0696d9d3';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Ground distance = grid distance ÷ CSF, where CSF = grid scale factor × elevation factor; ground is usually longer than grid.','Orthometric height H = h − N: subtract the (often negative) geoid undulation from the ellipsoidal height.','Inverse: distance = hypot(ΔE, ΔN); azimuth = atan2(ΔE, ΔN), normalized to 0–360°.','Always carry units and a sketch; estimate the answer''s magnitude before computing to catch gross errors.']::text[], learning_objectives=ARRAY['Solve mixed FS/SIT computational problems across coordinate systems, geodesy, curves, and photogrammetry.','Convert between grid and ground distances using the combined scale factor.','Compute orthometric height from ellipsoidal height and geoid undulation (H = h − N).','Apply the inverse to compute distance and azimuth between coordinate pairs.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7487b90f-db5e-4144-ae61-de244ccc6ef1';
DELETE FROM lesson_blocks WHERE lesson_id='7487b90f-db5e-4144-ae61-de244ccc6ef1';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=25, key_takeaways=ARRAY['The FS exam is computer-based, multiple-choice, with a supplied reference handbook—know the handbook''s layout, not just the formulas.','Triage: answer easy questions first, flag and return to hard ones; never leave a blank (no penalty for guessing).','Guard against trap answers by checking units, estimating magnitude, and confirming the scale-factor/sign direction.','Budget roughly the same time per question; if stuck past your budget, mark and move on.']::text[], learning_objectives=ARRAY['Describe the FS/SIT exam format, timing, and the use of the supplied reference handbook.','Apply time-management and triage strategies during the exam.','Use unit-checking, estimation, and answer-screening to avoid common computational traps.','Build an effective final-week and exam-day preparation plan.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='cc4a39c2-d573-4a23-be15-0b43ebd31774';
DELETE FROM lesson_blocks WHERE lesson_id='cc4a39c2-d573-4a23-be15-0b43ebd31774';
  'eeee2650-0000-0000-0000-000000000001', 'Grid distance to ground distance via combined scale factor', 'Grid distance to ground distance via combined scale factor', 'Geodetic — Coordinate Systems', 'Grid vs. ground', 'numeric_input', 'medium', 'A line measures {{grid:f2}} ft on the state plane grid. The grid scale factor is {{k:f6}} and the elevation (sea-level) factor is {{ef:f6}}. Using the combined scale factor, what is the ground distance (ft)?', 'grid / (k * ef)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"grid","type":"float","min":1500,"max":5000,"decimals":2},{"name":"k","type":"float","min":0.99988,"max":1.00002,"decimals":6},{"name":"ef","type":"float","min":0.99975,"max":0.99996,"decimals":6}]'::jsonb, '[{"name":"csf","formula":"k * ef"}]'::jsonb, '[{"step_number":1,"title":"Combined scale factor","formula":"CSF = k × elevation factor","calculation_template":"{{k:f6}} × {{ef:f6}} = {{csf:f6}}"},{"step_number":2,"title":"Convert grid to ground","formula":"ground = grid ÷ CSF","result_template":"{{grid:f2}} ÷ {{csf:f6}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Ground distance = grid ÷ CSF, where CSF = {{k:f6}} × {{ef:f6}} = {{csf:f6}}. So {{grid:f2}} ÷ {{csf:f6}} = {{_answer}} ft. Because CSF < 1, the ground distance is slightly longer than the grid distance.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000002', 'Orthometric height from ellipsoidal height and geoid undulation', 'Orthometric height from ellipsoidal height and geoid undulation', 'Geodetic — Heights', 'Orthometric height', 'numeric_input', 'easy', 'A GNSS observation gives an ellipsoidal height of {{h:f2}} m. The geoid model reports a geoid undulation of {{N:f2}} m at the point. What is the orthometric height H (m)?', 'h - N', '{"decimals":2,"unit":"m","tolerance":0.02}', '[{"name":"h","type":"float","min":150,"max":600,"decimals":2},{"name":"N","type":"float","min":-32,"max":-18,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply H = h − N","formula":"H = h − N","result_template":"{{h:f2}} − ({{N:f2}}) = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Orthometric height H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} m. Because N is negative here, subtracting it increases H.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000003', 'Horizontal circular curve — tangent distance', 'Horizontal circular curve — tangent distance', 'Construction — Horizontal Curves', 'Curve geometry', 'numeric_input', 'medium', 'A simple circular curve has a radius of {{R}} ft and an intersection angle I = {{I:f2}}°. What is the tangent distance T (ft)?', 'R * tan(toRad(I / 2))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":300,"max":1200},{"name":"I","type":"float","min":12,"max":60,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Half the intersection angle","calculation_template":"I/2 = {{I:f2}} / 2"},{"step_number":2,"title":"Tangent distance","formula":"T = R·tan(I/2)","result_template":"{{R}} × tan({{I:f2}}/2) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'T = R·tan(I/2) = {{R}} × tan({{I:f2}}°/2) = {{_answer}} ft. The PC lies T feet back from the PI along the back tangent.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000004', 'Horizontal circular curve — arc length', 'Horizontal circular curve — arc length', 'Construction — Horizontal Curves', 'Curve geometry', 'numeric_input', 'medium', 'A simple circular curve has a radius of {{R}} ft and an intersection angle I = {{I:f2}}°. What is the arc length L (ft)?', 'R * toRad(I)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":300,"max":1200},{"name":"I","type":"float","min":12,"max":60,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Convert I to radians","calculation_template":"toRad({{I:f2}}) = {{I:f2}} × π/180"},{"step_number":2,"title":"Arc length","formula":"L = R·I(rad)","result_template":"{{R}} × toRad({{I:f2}}) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Arc length L = R·I in radians = {{R}} × toRad({{I:f2}}°) = {{_answer}} ft. Station PT = PC + L (along the arc, not PI + T).', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000005', 'Ground Sample Distance (GSD) from flight parameters', 'Ground Sample Distance (GSD) from flight parameters', 'Photogrammetry — Imagery', 'GSD', 'numeric_input', 'hard', 'A UAS camera has a pixel pitch of {{p:f4}} mm and a focal length of {{f:f1}} mm, flying at {{H}} m above ground level. What is the Ground Sample Distance (cm/pixel)?', 'p * (H * 1000) / f / 10', '{"decimals":2,"unit":"cm/pixel","tolerance":0.05}', '[{"name":"p","type":"float","min":0.0024,"max":0.006,"decimals":4},{"name":"f","type":"float","min":16,"max":50,"decimals":1},{"name":"H","type":"integer","min":60,"max":150}]'::jsonb, '[{"name":"Hmm","formula":"H * 1000"},{"name":"gsdmm","formula":"p * H * 1000 / f"}]'::jsonb, '[{"step_number":1,"title":"Convert flight height to mm","calculation_template":"{{H}} m × 1000 = {{Hmm}} mm"},{"step_number":2,"title":"GSD in mm","formula":"GSD = p·H/f","calculation_template":"{{p:f4}} × {{Hmm}} ÷ {{f:f1}} = {{gsdmm:f2}} mm"},{"step_number":3,"title":"Convert to cm","result_template":"{{gsdmm:f2}} mm ÷ 10 = {{_answer}} cm/pixel"}]'::jsonb, '{"method":"none"}'::jsonb, 'GSD = (p × H) / f = ({{p:f4}} mm × {{Hmm}} mm) ÷ {{f:f1}} mm = {{gsdmm:f2}} mm = {{_answer}} cm/pixel. Lower flight height gives a smaller (finer) GSD.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000006', 'Inverse distance between two coordinate pairs', 'Inverse distance between two coordinate pairs', 'Geodetic — Coordinate Geometry', 'Inverse', 'numeric_input', 'easy', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). What is the horizontal distance from A to B (ft)?', 'hypot(de, dn)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"n1","type":"float","min":4000,"max":6000,"decimals":2},{"name":"e1","type":"float","min":3000,"max":5000,"decimals":2},{"name":"dn","type":"float","min":150,"max":600,"decimals":2},{"name":"de","type":"float","min":150,"max":600,"decimals":2}]'::jsonb, '[{"name":"n2","formula":"n1 + dn"},{"name":"e2","formula":"e1 + de"}]'::jsonb, '[{"step_number":1,"title":"Coordinate differences","calculation_template":"ΔN = {{dn:f2}}, ΔE = {{de:f2}}"},{"step_number":2,"title":"Inverse distance","formula":"d = hypot(ΔE, ΔN)","result_template":"sqrt({{de:f2}}² + {{dn:f2}}²) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The inverse distance = hypot(ΔE, ΔN) = sqrt({{de:f2}}² + {{dn:f2}}²) = {{_answer}} ft. Azimuth would be atan2(ΔE, ΔN), normalized to 0–360°.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
  'eeee2650-0000-0000-0000-000000000007', 'Vertical curve elevation at a station past the BVC', 'Vertical curve elevation at a station past the BVC', 'Construction — Vertical Curves', 'Profile elevation', 'numeric_input', 'hard', 'An equal-tangent vertical curve of length {{L}} stations joins an incoming grade g1 = {{g1:f2}}% to an outgoing grade g2 = {{g2:f2}}%. The BVC elevation is {{ebvc:f2}} ft. What is the curve elevation {{x:f2}} stations past the BVC (ft)?', 'ebvc + g1 * x + (g2 - g1) / (2 * L) * x * x', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"L","type":"integer","min":4,"max":10},{"name":"g1","type":"float","min":1,"max":4,"decimals":2},{"name":"g2","type":"float","min":-4,"max":-1,"decimals":2},{"name":"ebvc","type":"float","min":500,"max":900,"decimals":2},{"name":"x","type":"float","min":1,"max":3,"decimals":2}]'::jsonb, '[{"name":"A","formula":"g2 - g1"}]'::jsonb, '[{"step_number":1,"title":"Grade difference","formula":"A = g2 − g1","calculation_template":"{{g2:f2}} − {{g1:f2}} = {{A:f2}}%"},{"step_number":2,"title":"Parabolic elevation","formula":"y = Ebvc + g1·x + (A/2L)·x²","result_template":"{{ebvc:f2}} + {{g1:f2}}×{{x:f2}} + ({{A:f2}}/(2×{{L}}))×{{x:f2}}² = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'On an equal-tangent vertical curve, elevation = Ebvc + g1·x + (A/2L)·x² with A = g2 − g1 = {{A:f2}}%, x and L in stations. Result = {{_answer}} ft.', 'c100001a-0000-0000-0000-00000000001a', ARRAY['buildout','module-26','practice']::text[], true, 'buildout:m26');
COMMIT;
SELECT 'm26 SIT Exam Review — Advanced Topics: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c100001a-0000-0000-0000-00000000001a') || ' blocks.' AS status;