INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000000', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'text', '{"html":"<h3>What boundary law tests on the SIT</h3><p>The boundary-law portion of the SIT/FS exam rewards <strong>principles and priorities</strong>, not memorized statutes. Almost every question reduces to one idea: a retracing surveyor''s job is to find <em>where the boundary already is</em>&mdash;the location the original parties created and accepted&mdash;not to compute a new ''better'' line. You are gathering and weighing evidence. When the written words of a deed conflict with the marks on the ground, a hierarchy tells you which controls. Expect short scenario questions (''a fence has stood 40 years'', ''the deed calls for an iron pin but none is found'', ''two deeds overlap'') where the right answer is the principle that resolves the conflict. This lesson is a high-yield refresher; the underlying doctrines were developed in Modules 13&ndash;15.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000001', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'text', '{"html":"<h3>Priority of calls</h3><p>When the elements of a description disagree, retracement follows a <strong>priority of calls</strong>. The classic Texas ordering from <em>Stafford v. King</em> (1867) is: <strong>(1) natural monuments</strong> (rivers, rock outcrops, established trees), <strong>(2) artificial monuments</strong> (iron pins, set stones, fences relied on), <strong>(3) calls for adjoinder</strong> (the line of an adjoining senior survey), <strong>(4) course / bearing</strong>, <strong>(5) distance</strong>, then <strong>(6) area or quantity</strong>. Higher elements control lower ones because they are harder to fabricate and better reflect what the parties saw and intended. But the hierarchy is a <em>presumption</em>, not a straitjacket: it yields to the clearly expressed intent of the grant and to evidence that a lower element is more reliable in the specific case.</p><ul><li><strong>Monuments over measurements</strong> is the single most-tested idea.</li><li><strong>Distance is weak</strong>&mdash;it is the easiest element to mis-measure and is routinely overridden by a found monument.</li><li><strong>Area/quantity is the weakest</strong> and almost never controls.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000002', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'callout', '{"type":"warning","text":"Texas differs: many state exams cite the general common-law order, but Texas grounds its priority of calls in Stafford v. King (1867). Same idea—natural monuments down to quantity—but cite the Texas case if the question is Texas-specific."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000003', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'table', '{"headers":["Doctrine","Core rule","Typical exam trigger"],"rows":[["Senior rights","First deed out of a common grantor gets its full record dimensions; junior takes the remainder.","Two adjoining deeds overlap or leave a gap"],["Footsteps / retracement","Find and honor the original surveyor''s lines and corners, even if erroneous.","Found original monument disagrees with record distance"],["Priority of calls","Natural mon. > artificial mon. > adjoinder > bearing > distance > area.","Deed elements conflict"],["Proportionate measurement","Distribute excess/deficiency in proportion to record between found original corners.","Block of lots measures long or short"],["Unwritten title","Adverse possession / acquiescence / estoppel can move a line off the record.","Long-standing fence or occupation"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000004', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'text', '{"html":"<h3>Proportionate measurement</h3><p>When the total distance between two <em>found original</em> corners differs from the record (excess or deficiency), and no intervening original monuments survive, the difference is distributed by <strong>proportionate (relative) measurement</strong>. Each interior interval keeps its <em>record proportion</em> of the measured total. <strong>Single proportion</strong> distributes along one line; <strong>double proportion</strong> (used for lost PLSS section corners) balances between the four controlling corners north&ndash;south and east&ndash;west. The key exam distinction: a corner is <strong>lost</strong> (re-set by proportion) only when its position cannot be recovered from <em>any</em> acceptable evidence. If it can be recovered&mdash;by an existing monument, by accessories, or by reliable testimony&mdash;it is merely <strong>obliterated</strong>, and you recover it from the evidence rather than proportioning. Never proportion away a found original monument.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000005', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'callout', '{"type":"info","text":"Lost vs. obliterated is a favorite trap: ''obliterated'' corners are RECOVERED from evidence; only ''lost'' corners are RESTORED by proportionate measurement."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000006', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Single proportionate measurement distributing excess across a block of equal record lots."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0001-0000-0000-000000000007', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'key_takeaways', '{"title":"Key Takeaways","items":["Retracement honors the original footsteps; you locate the existing boundary, not a new one.","Priority of calls: natural > artificial monuments > adjoinder > bearing > distance > area, subject to intent.","Senior rights: earliest conveyance from a common grantor controls; junior takes the remainder.","Distribute excess/deficiency by proportion; recover obliterated corners from evidence but restore only lost corners by proportioning."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000000', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'text', '{"html":"<h3>Why descriptions matter on the exam</h3><p>A legal description is the written half of a boundary; the monuments are the physical half. The exam tests whether you can <strong>read a description, locate the parcel, and detect defects</strong>. In Texas, the dominant form is <strong>metes-and-bounds</strong> because most land traces to Spanish/Mexican grants and Republic/State patents rather than a federal PLSS grid. Even modern subdivisions ultimately rest on a metes-and-bounds boundary of the parent tract. Know the anatomy of a call set and the rules courts use when the words are unclear.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000001', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'text', '{"html":"<h3>Anatomy of a metes-and-bounds description</h3><p>A complete metes-and-bounds description contains: a <strong>caption</strong> (county, survey/abstract, parent tract), a clearly fixed <strong>Point of Beginning (POB)</strong> tied to an identifiable monument or coordinate, a series of <strong>calls</strong> (each a bearing and distance, often with a monument call: ''N 45&deg;00'' E, 150.00 ft to a 1/2-inch iron rod set''), and a <strong>closing call</strong> returning to the POB (''thence ... to the Point of Beginning''). The perimeter should <strong>close</strong> mathematically. A good description also recites <strong>area</strong> and <strong>basis of bearings</strong>. Watch for:</p><ul><li>Calls that recite both a monument and a bearing/distance&mdash;if they disagree, the <strong>monument controls</strong>.</li><li>A ''more or less'' on the area&mdash;area is the weakest element and yields to the perimeter.</li><li>Missing or floating POB&mdash;fatal unless cured by reference to a plat or adjoiner.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000002', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'table', '{"headers":["Description type","How it identifies the parcel","Common use"],"rows":[["Metes-and-bounds","Perimeter traced by bearing/distance and monument calls from a POB.","Texas norm; original tracts, splits, easements"],["Lot-and-block (platted)","Reference to a recorded subdivision plat (Lot 7, Block C, of ...).","Subdivisions"],["Strip / centerline","A baseline or centerline with offsets/widths (roads, pipelines).","Linear easements, ROW"],["PLSS aliquot","Quarter/quarter-quarter of a section, township, range.","Federal-survey states (rare in Texas)"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000003', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'text', '{"html":"<h3>Rules of construction for ambiguous descriptions</h3><p>When a description is unclear, courts and surveyors apply settled <strong>rules of construction</strong> to find the parties'' intent: (1) the instrument is read <strong>as a whole</strong>; (2) <strong>specific calls control general calls</strong> (a monument call governs a mere bearing/distance); (3) where words conflict with figures, the controlling element is the one most consistent with intent; (4) a description is construed <strong>against the grantor</strong> who wrote it; and (5) <strong>patent</strong> ambiguities (apparent on the face, e.g., a call to a nonexistent monument with no other clue) may void the deed, while <strong>latent</strong> ambiguities (clear on the page but failing on the ground) are resolved with <strong>extrinsic evidence</strong>. The surveyor''s task is to harmonize&mdash;reject an element only when it cannot be reconciled.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000004', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'callout', '{"type":"info","text":"Exam tip: ''specific controls general'' and ''monument controls bearing/distance'' are the same idea wearing two hats. If a call names a found monument, that location wins."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0002-0000-0000-000000000005', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'key_takeaways', '{"title":"Key Takeaways","items":["Metes-and-bounds is the Texas standard; know POB, calls, closing call, basis of bearings, and area.","Specific/monument calls control general bearing-distance calls; the deed is read as a whole for intent.","Area (''more or less'') is the weakest element and yields to the perimeter.","Patent ambiguity can void a description; latent ambiguity is cured with extrinsic evidence."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0003-0000-0000-000000000000', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'text', '{"html":"<h3>Where Texas land titles come from</h3><p>Unlike public-land (PLSS) states, Texas kept its public domain when it joined the Union, so Texas titles trace to a <strong>sovereign grant</strong>&mdash;Spanish, Mexican, Republic of Texas, or State of Texas&mdash;rather than to a federal township-and-range survey. The original act that severed land from the sovereign is the <strong>patent</strong> (or grant). The <strong>General Land Office (GLO)</strong> is the archive: it holds the original <strong>field notes</strong>, sketches, and patents, organized by <strong>survey</strong> and <strong>abstract number</strong> within each county. For retracement, the GLO record is often your best evidence of the original surveyor''s footsteps.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0003-0000-0000-000000000001', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'text', '{"html":"<h3>GLO vs. county records</h3><p>Two record systems matter. The <strong>GLO</strong> governs the <em>origin</em> of title&mdash;original grants, patents, and the field notes that define the original survey boundaries. The <strong>county clerk</strong> governs <em>subsequent</em> conveyances&mdash;the deeds, plats, easements, and liens recorded in the Official Public Records (Deed Records). To research a parcel you typically pull the current deed at the county, run the chain backward grantor-to-grantee, identify the original survey and abstract, then go to the GLO for the original field notes. A complete <strong>chain of title</strong> runs from the sovereign grant all the way to the present owner with no gaps.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0003-0000-0000-000000000002', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'callout', '{"type":"warning","text":"Texas differs: there is no federal PLSS for original Texas land. References to ''sections, townships, and ranges'' generally do not apply; Texas uses surveys, leagues/labors, and abstract numbers archived at the GLO."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0003-0000-0000-000000000003', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'text', '{"html":"<h3>The recording act and bona fide purchasers</h3><p>Texas is a <strong>notice</strong> recording state (Property Code &sect;13.001). An unrecorded conveyance or lien is <strong>void as to a subsequent bona fide purchaser (BFP)</strong> for valuable consideration who takes <em>without notice</em> of the prior interest. Recording an instrument gives <strong>constructive notice</strong> to the world, protecting the grantee''s priority. ''Notice'' includes actual, constructive (record), and inquiry notice&mdash;visible possession or a fence can be enough to put a buyer on inquiry. For the surveyor, the lesson is practical: the record is not always complete, and what is <em>on the ground</em> (occupation, monuments) can carry legal weight even when it is not in the deed records.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0003-0000-0000-000000000004', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'key_takeaways', '{"title":"Key Takeaways","items":["Texas titles begin with a sovereign grant/patent archived at the GLO, organized by survey and abstract number.","The GLO holds original field notes and patents; the county clerk records later deeds, plats, and liens.","Texas is a notice state: recording gives constructive notice and protects a BFP without notice (Prop. Code §13.001).","Retracement research runs the chain backward from current deed to the original grant, gathering field notes and adjoiner deeds."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000000', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'text', '{"html":"<h3>Construction layout on the exam</h3><p>Construction questions are <strong>computational and formula-driven</strong>&mdash;you stake what the engineer designed. The two big topics are <strong>horizontal curves</strong> (circular arcs joining two tangents) and <strong>vertical curves</strong> (parabolas joining two grades). You should be able to start from the given design elements (PI station, radius, intersection angle, grades, curve length) and produce the layout values: tangent length, curve length, key-point stations, and elevations. Memorize the small set of curve formulas&mdash;they appear on nearly every FS/SIT exam.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000001', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'equation', '{"latex":"T = R\\tan\\!\\frac{I}{2}, \\quad L = R\\,I_{rad} = R\\cdot\\frac{\\pi I}{180}, \\quad LC = 2R\\sin\\!\\frac{I}{2}","label":"Horizontal circular curve — tangent, arc length, long chord","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000002', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'text', '{"html":"<h3>Horizontal curve geometry</h3><p>A simple circular curve is defined by its <strong>radius R</strong> and <strong>intersection (deflection) angle I</strong>. From those: the <strong>tangent T</strong> = R&middot;tan(I/2) is the distance from the PI back to the PC (and forward to the PT); the <strong>arc length L</strong> = R&middot;I in radians; the <strong>long chord LC</strong> = 2R&middot;sin(I/2). Two more layout values: the <strong>middle ordinate M</strong> = R(1 &minus; cos(I/2)) and the <strong>external distance E</strong> = R(sec(I/2) &minus; 1). Stationing is <em>continuous along the alignment</em>, so you must walk the curve, not the tangents: <strong>Sta PC = Sta PI &minus; T</strong> and <strong>Sta PT = Sta PC + L</strong>. The most common error is computing PT as PI + T&mdash;wrong, because the alignment runs along the arc, which is shorter than going out to the PI and back.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000003', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'callout', '{"type":"warning","text":"Common trap: PT = PC + L (arc), NOT PI + T. Walking out to the PI and back overstates the alignment length by 2T − L."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000004', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'equation', '{"latex":"y = g_1 x + \\frac{(g_2 - g_1)}{2L}x^2, \\qquad x_{turn} = \\frac{-g_1 L}{g_2 - g_1}","label":"Equal-tangent vertical curve — elevation and turning point","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000005', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'text', '{"html":"<h3>Vertical curves</h3><p>An equal-tangent vertical curve is a <strong>parabola</strong> joining an incoming grade g1 to an outgoing grade g2 over length L. Let the algebraic grade difference be <strong>A = g2 &minus; g1</strong> (in percent). The elevation at a distance x (in stations) past the <strong>BVC</strong> is <strong>Elev = Elev<sub>BVC</sub> + g1&middot;x + (A/2L)&middot;x&sup2;</strong>, with grades expressed as percent and x, L in stations of 100 ft. The <strong>high or low point</strong> occurs where the slope is zero, at x = &minus;g1&middot;L / A (stations from BVC); it exists on the curve only if g1 and g2 have opposite signs. A crest curve (g1 &gt; 0, g2 &lt; 0) has a high point; a sag curve has a low point&mdash;critical for drainage and sight distance.</p>"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000006', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'text', '{"html":"<h3>Grade, offset, and slope stakes</h3><p>Layout in the field is delivered through stakes. A <strong>grade stake</strong> (or hub-and-tack with a guard) carries a marked <strong>cut or fill</strong> to design grade at that station. <strong>Offset stakes</strong> are set a known horizontal distance off the centerline (so they survive excavation) and reference the centerline grade plus the offset. <strong>Slope stakes</strong> mark the <em>catch point</em>&mdash;where the designed cut or fill slope (e.g., 2:1) intersects existing ground&mdash;and are set by trial: estimate the offset, measure ground, recompute, repeat until the slope closes on the ground. Always label whether the figure is a <strong>cut</strong> (remove material) or <strong>fill</strong> (add material) and to which surface (subgrade vs. finished).</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000007', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Simple circular curve elements—PI, PC, PT, T, L, LC, and intersection angle I."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0004-0000-0000-000000000008', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'key_takeaways', '{"title":"Key Takeaways","items":["T = R·tan(I/2), L = R·toRad(I), LC = 2R·sin(I/2); also M = R(1−cos(I/2)), E = R(sec(I/2)−1).","Station the alignment along the arc: PC = PI − T, PT = PC + L.","Vertical curve: Elev = Elev_BVC + g1·x + (A/2L)·x², high/low at x = −g1·L/A.","Field stakes carry cut/fill; slope stakes locate the catch point of the design slope on existing ground."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000000', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'text', '{"html":"<h3>Topographic surveying scope</h3><p>A topographic survey captures the <strong>shape of the ground</strong> and the features on it&mdash;elevations, breaklines, drainage, and improvements&mdash;and delivers a surface model and contours. The exam tests <strong>method selection</strong> (total station vs. RTK GNSS vs. LiDAR vs. photogrammetry), <strong>contour interpretation</strong>, and a few computations, most notably <strong>Ground Sample Distance (GSD)</strong> for aerial/UAS work. The governing principle is fitness for purpose: pick the data density and accuracy that resolve the smallest feature the design cares about.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000001', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'table', '{"headers":["Method","Typical accuracy","Best for"],"rows":[["Total station (RTS)","few mm + ppm","Hard detail, high accuracy, obstructed sky"],["RTK / network GNSS","~1.5–3 cm horiz, 3–5 cm vert","Open-sky topo, large areas, fast"],["Airborne / mobile LiDAR","~3–15 cm","Large corridors, vegetation penetration"],["UAS photogrammetry","1–5 cm (GSD-dependent)","Small sites, surfaces/orthophotos, volumes"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000002', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'equation', '{"latex":"GSD = \\frac{p \\cdot H}{f}","label":"Ground Sample Distance (p = pixel pitch, H = flight height AGL, f = focal length)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000003', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'text', '{"html":"<h3>Ground Sample Distance (GSD)</h3><p>For aerial and UAS imagery, the <strong>GSD</strong> is the ground distance represented by one image pixel&mdash;the practical resolution of the survey. It follows directly from similar triangles: <strong>GSD = (p &times; H) / f</strong>, where <strong>p</strong> is the sensor''s pixel pitch (physical size of one pixel on the chip), <strong>H</strong> is the flying height above ground level, and <strong>f</strong> is the lens focal length (same units as p, e.g., mm). Lower flight = smaller GSD = finer detail, at the cost of more images and flight time. A common planning rule: choose H so the GSD is roughly half the smallest feature you must resolve. Keep units consistent&mdash;if p is in mm and f is in mm, H and GSD share the same length unit.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000004', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'text', '{"html":"<h3>Reading contours</h3><p>Contours are lines of equal elevation, and they obey rules the exam loves: they <strong>never cross or branch</strong> (a single contour has one elevation); they <strong>close on themselves</strong> or run off the sheet; <strong>spacing encodes slope</strong>&mdash;closely spaced contours are steep, widely spaced are flat; they form a <strong>''V'' pointing upstream</strong> when crossing a drainage and a <strong>''V'' or ''U'' pointing downhill</strong> on a ridge; and concentric closed contours indicate a hill (or, with hachures, a depression). Pick a <strong>contour interval</strong> matched to relief and scale&mdash;too coarse hides grade, too fine clutters. Distinguish the surface models: a <strong>DTM/DEM</strong> is bare earth; a <strong>DSM</strong> includes vegetation and buildings. <strong>Breaklines</strong> (curbs, ditch flowlines, ridges) force the triangulated surface to honor abrupt grade changes.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000005', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'callout', '{"type":"info","text":"Exam tip: contours ''V upstream''—the point of the V aims up the valley toward higher ground. On a ridge the V points downhill. Closely spaced = steep."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0005-0000-0000-000000000006', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'key_takeaways', '{"title":"Key Takeaways","items":["Match collection method and density to the smallest feature the design requires.","GSD = (pixel pitch × flight height) / focal length; lower flight gives finer GSD.","Contours never cross; spacing shows slope; they V upstream across drainages.","DTM/DEM = bare earth, DSM = surface with features; breaklines enforce grade breaks."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0006-0000-0000-000000000000', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'text', '{"html":"<h3>The surveyor as a professional</h3><p>Licensure exists to <strong>protect the public</strong>: a surveyor''s work fixes property rights and public safety, so the law imposes duties beyond ordinary contract. The exam tests your grasp of the <strong>standard of care</strong>, the <strong>code of ethics</strong>, and the basics of <strong>liability and business practice</strong>. The recurring theme is that the surveyor owes duties to the client, to third parties who foreseeably rely on the work, and to the public&mdash;and that those duties are measured against what a competent peer would do.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0006-0000-0000-000000000001', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'text', '{"html":"<h3>Standard of care and ethics</h3><p>The <strong>standard of care</strong> is the degree of skill and diligence a <em>reasonably prudent surveyor</em> would exercise under the same circumstances&mdash;not perfection, but competence consistent with prevailing practice and the applicable standards (in Texas, 22 TAC Ch. 138 standards of practice). Core ethical duties flow from this:</p><ul><li><strong>Competence</strong>: practice only within your area of expertise; decline or associate help otherwise.</li><li><strong>Independence / objectivity</strong>: serve as a faithful agent but never falsify or shade results to please a client.</li><li><strong>Confidentiality</strong>: protect client information.</li><li><strong>Honesty in certifications</strong>: sign and seal only work you performed or supervised, and certify only what you actually determined.</li></ul><p>A certification is a professional representation&mdash;sealing a survey you did not control, or certifying beyond what you measured, is both an ethics violation and a liability exposure.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0006-0000-0000-000000000002', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'callout', '{"type":"warning","text":"Texas differs: the binding ethical and technical standards are TBPELS rules in 22 TAC Ch. 138 (with the TSPS Manual of Practice as guidance). Cite the TAC standards on Texas-specific questions."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0006-0000-0000-000000000003', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'text', '{"html":"<h3>Liability and business practice</h3><p>Most professional claims sound in <strong>negligence</strong> or <strong>breach of contract</strong>. Negligence has four elements: a <strong>duty</strong>, a <strong>breach</strong> (falling below the standard of care), <strong>causation</strong>, and <strong>damages</strong>. Standards of practice matter because they help a court define the duty&mdash;violating a published standard is strong evidence of breach. Protect yourself with sound business practice: a <strong>written contract</strong> that defines <strong>scope, deliverables, and limitations</strong>; clear, accurate <strong>certifications</strong> matched to the work; adequate <strong>records and field-note retention</strong>; and professional liability (E&amp;O) insurance. A precise scope statement is your best defense&mdash;most disputes arise from unmet expectations the contract never addressed.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0006-0000-0000-000000000004', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'key_takeaways', '{"title":"Key Takeaways","items":["The surveyor''s paramount duty is to protect the public; the legal measure is the standard of care of a reasonably prudent surveyor.","Ethics: competence within expertise, independence, confidentiality, and honest certifications—seal only work you controlled.","Negligence = duty + breach + causation + damages; published standards help define the duty.","A written contract defining scope and deliverables, plus good records, is the strongest liability protection."]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000000', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'text', '{"html":"<h3>The Texas regulatory framework in one view</h3><p>This lesson consolidates the Texas-specific law an SIT must carry into the exam. Three pillars define the regulatory side: the <strong>agency</strong> (TBPELS, the Texas Board of Professional Engineers and Land Surveyors), the <strong>statute</strong> (Occupations Code <strong>Ch. 1071</strong>, the Professional Land Surveying Practices Act), and the <strong>rules</strong> (Texas Administrative Code, Title 22, <strong>Ch. 138</strong>, standards of practice and conduct). The statute creates the license and the discipline power; the rules implement it. Memorize these three anchors&mdash;most ''which body governs?'' questions resolve to them.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000001', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'table', '{"headers":["Credential","What it permits","Note"],"rows":[["SIT (Surveyor-in-Training)","Work under an RPLS while gaining experience; passed the FS exam.","Intern step toward RPLS"],["RPLS (Registered Professional Land Surveyor)","Independent boundary surveying; seal surveys and descriptions.","Standard Texas license"],["LSLS (Licensed State Land Surveyor)","Survey original state-land grant boundaries; file field notes in the GLO.","Additional credential beyond RPLS"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000002', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'text', '{"html":"<h3>Texas boundary doctrines worth memorizing</h3><p>On the substantive side, Texas applies several well-settled doctrines: the <strong>priority of calls</strong> (natural monuments &gt; artificial monuments &gt; adjoinder &gt; bearing &gt; distance &gt; area) grounded in <strong>Stafford v. King</strong>; <strong>senior rights</strong> for conflicting deeds from a common grantor; and the <strong>notice recording act</strong> (Prop. Code &sect;13.001) protecting a bona fide purchaser. For water boundaries, the line follows the <strong>gradient boundary</strong> on navigable streams; a riparian boundary <strong>moves with slow, imperceptible accretion and erosion</strong> but <strong>does not move with avulsion</strong> (a sudden, perceptible shift), where the old boundary is retained. Texas titles trace to <strong>sovereign grants and patents</strong> archived at the GLO, not to a federal PLSS&mdash;so ''townships and ranges'' generally do not apply.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000003', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'callout', '{"type":"warning","text":"Texas differs (units/history): Texas uses the vara (~33⅓ inches) in old grants and the league/labor for grant areas; original boundaries trace to Spanish/Mexican/Republic grants—not PLSS sections. Watch for vara-based record distances."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000004', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'text', '{"html":"<h3>Water boundaries: accretion vs. avulsion</h3><p>Riparian boundary rules are heavily tested. Where land borders water, the boundary generally <strong>moves with the water</strong> when the change is <strong>slow and imperceptible</strong>&mdash;<strong>accretion</strong> (gradual deposit, owner gains) and <strong>erosion</strong> (gradual loss, owner loses). The boundary <strong>does not move</strong> when the change is <strong>sudden and perceptible</strong>&mdash;<strong>avulsion</strong>, where the old boundary line is fixed in place even though the water has shifted. <strong>Reliction</strong> (gradual withdrawal of water exposing land) is treated like accretion. On navigable Texas streams, the legal line is the <strong>gradient boundary</strong> (a mid-bank line defined by the water''s gradient), and the bed below it may belong to the State. These rules turn on the <em>rate</em> of change, so exam scenarios hinge on whether the shift was gradual or sudden.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0007-0000-0000-000000000005', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'key_takeaways', '{"title":"Key Takeaways","items":["Framework: TBPELS agency, Occupations Code Ch. 1071 statute, 22 TAC Ch. 138 rules.","Credentials: SIT → RPLS → LSLS (LSLS for original state-land boundaries and GLO field notes).","Priority of calls (Stafford v. King) and senior rights govern boundary conflicts; titles trace to sovereign grants.","Accretion/erosion (gradual) move the boundary; avulsion (sudden) does not; navigable streams use the gradient boundary."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000000', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'text', '{"html":"<h3>How to attack the computational set</h3><p>This set drills the high-frequency calculations on the FS/SIT exam. For each problem: <strong>sketch it</strong>, <strong>write the governing formula</strong>, <strong>list knowns with units</strong>, <strong>estimate the answer</strong>, then compute. Estimating first catches the classic blunders&mdash;dividing when you should multiply, or applying a scale factor the wrong way. The worked templates below (and the module''s practice generator) cover grid/ground conversion via the combined scale factor, orthometric height, horizontal-curve geometry, GSD, the coordinate inverse, and vertical-curve elevation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000001', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'equation', '{"latex":"D_{ground} = \\frac{D_{grid}}{CSF}, \\quad CSF = k \\cdot \\frac{R}{R+h}","label":"Grid↔ground via combined scale factor (k = grid scale factor, h = elevation)","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000002', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'text', '{"html":"<h3>Grid vs. ground</h3><p>State plane coordinates live on a <strong>grid</strong>: a conformal projection (Lambert or transverse Mercator) of a flat plane scaled to the ellipsoid. To convert a measured <strong>ground</strong> distance to grid (or back), apply the <strong>combined scale factor (CSF)</strong> = <strong>grid scale factor (k)</strong> &times; <strong>elevation (sea-level) factor</strong>, where the elevation factor &asymp; R/(R+h). Because both factors are usually slightly less than 1, <strong>grid distances are typically shorter than ground</strong>: <strong>D<sub>ground</sub> = D<sub>grid</sub> / CSF</strong> and <strong>D<sub>grid</sub> = D<sub>ground</sub> &times; CSF</strong>. The most common exam mistake is applying the factor in the wrong direction&mdash;remember that going up to the ground (higher elevation, real-world distance) makes the distance <em>longer</em>, so you <em>divide</em> grid by CSF.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000003', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'equation', '{"latex":"H = h - N","label":"Orthometric height from ellipsoidal height and geoid undulation","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000004', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'text', '{"html":"<h3>Orthometric height (H = h − N)</h3><p>GNSS gives <strong>ellipsoidal height h</strong> (above the reference ellipsoid). What we use for grades and drainage is <strong>orthometric height H</strong> (above the geoid, i.e., ''mean sea level''). They differ by the <strong>geoid undulation N</strong>, the geoid&minus;ellipsoid separation: <strong>H = h &minus; N</strong>. In the conterminous U.S., N is generally <em>negative</em> (the geoid lies below the ellipsoid), so subtracting a negative N <em>increases</em> H. Watch the sign carefully&mdash;mis-handling the sign of N is the most common error. A geoid model (e.g., GEOID18) supplies N at your location.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000005', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'callout', '{"type":"info","text":"Exam tip for the inverse: azimuth = atan2(ΔE, ΔN) with ΔE = E2−E1 and ΔN = N2−N1; add 360° if negative. Note ΔE is the FIRST argument (east over north)."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000006', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Relationship of ellipsoidal height h, geoid undulation N, and orthometric height H (H = h − N)."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0008-0000-0000-000000000007', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'key_takeaways', '{"title":"Key Takeaways","items":["Ground = grid ÷ CSF; grid = ground × CSF; CSF = grid scale factor × elevation factor.","H = h − N; in the U.S. N is usually negative, so H comes out larger than h.","Inverse: distance = hypot(ΔE, ΔN), azimuth = atan2(ΔE, ΔN) normalized to 0–360°.","Sketch, estimate, and track units before computing to catch gross errors."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000000', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'text', '{"html":"<h3>Know the format before you study</h3><p>The <strong>Fundamentals of Surveying (FS)</strong> exam&mdash;the gateway to becoming an SIT&mdash;is a <strong>computer-based, multiple-choice</strong> exam administered by NCEES, with a generous time allowance split across the day and a built-in break. Critically, it is <strong>open to a supplied reference handbook only</strong>: you do not bring your own materials, and the handbook contains the equations and constants you are expected to use. The single highest-leverage prep step is to <strong>study the NCEES FS Reference Handbook itself</strong>&mdash;learn where each topic, formula, and table lives so you can find them in seconds under time pressure. Knowing a formula is worthless if you waste two minutes locating it.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000001', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'text', '{"html":"<h3>Time management and triage</h3><p>With a fixed number of questions and a fixed clock, <strong>pace</strong> is everything. Compute a rough <strong>per-question budget</strong> (total time &divide; number of questions) and respect it. Make <strong>two passes</strong>: on the first pass, answer every question you can solve quickly and <strong>flag</strong> the rest; on the second pass, return to flagged items with the time that remains. <strong>Never leave a blank</strong>&mdash;there is no penalty for guessing, so a marked-and-moved question still gets an answer. If you are past your budget on a single problem, mark it and move on; one hard problem is not worth three easy ones you never reached.</p><ul><li>Easy first, hard flagged.</li><li>One per budget; if stuck, guess and flag.</li><li>Reserve the last minutes to ensure no blanks remain.</li></ul>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000002', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'callout', '{"type":"info","text":"Exam tip: distractor answers are often the result of a predictable error (wrong scale-factor direction, wrong sign on N, PI+T instead of PC+L, degrees vs. radians). Recognizing the trap tells you which answer NOT to pick."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000003', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'text', '{"html":"<h3>Avoiding computational traps</h3><p>Most wrong answers on a well-written exam are <strong>deliberate traps</strong> built from common mistakes. Defend against them with three habits: <strong>check units</strong> (a feet/meters mix-up is the most common slip), <strong>estimate the magnitude</strong> before computing (is the answer plausibly that big?), and <strong>verify direction/sign</strong> on the operations that flip students&mdash;dividing vs. multiplying by a scale factor, the sign of the geoid undulation, stationing along the arc (PC + L) versus the tangent (PI + T), and degrees vs. radians in trig. When two answer choices differ by exactly a known factor, that gap usually signals a units or scale-factor trap. Reading every question twice&mdash;once for the scenario, once for exactly what is asked (e.g., ''ground'' vs. ''grid'', ''cut'' vs. ''fill'')&mdash;catches the rest.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000004', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'text', '{"html":"<h3>Final-week and exam-day plan</h3><p>In the last week, shift from learning new material to <strong>full-length timed practice</strong> and <strong>handbook navigation drills</strong>. Sleep and logistics matter: confirm your test center, ID, and start time; the night before, rest rather than cram. On exam day, arrive early, do an easy warm-up problem first to settle nerves, take the scheduled break, hydrate, and keep moving&mdash;momentum beats perfection. Trust your two-pass system; a calm, well-paced test-taker who never leaves a blank will outperform a faster one who panics on hard problems.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee2610-0009-0000-0000-000000000005', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'key_takeaways', '{"title":"Key Takeaways","items":["The FS exam is computer-based MC with a supplied reference handbook—master the handbook''s layout.","Use a per-question time budget and a two-pass (easy-first, flag-the-rest) strategy; never leave a blank.","Beat trap answers with unit checks, magnitude estimates, and sign/direction verification.","In the final week, do timed full-length practice and handbook drills; rest and arrive early on exam day."]}'::jsonb, 5);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000001', 'Priority of calls', 'The hierarchy used when deed elements conflict: natural monuments > artificial monuments > calls for adjoinder > course (bearing) > distance > area/quantity, all subordinate to the grant''s intent.', 'Monuments beat measurements.', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000002', 'Senior rights', 'When two parcels are carved from a common grantor, the parcel conveyed first (senior) is entitled to its full record dimensions; the later (junior) parcel takes whatever remains.', 'First out the door wins.', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000003', 'Lost vs. obliterated corner', 'An obliterated corner has no remaining physical mark but can be recovered from acceptable evidence (accessories, testimony); a lost corner cannot be recovered from any evidence and must be restored by proportionate measurement.', NULL, 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000004', 'Point of Beginning (POB)', 'The fixed starting point of a metes-and-bounds description, tied to an identifiable monument or coordinate, to which the closing call returns.', 'Where the perimeter starts and ends.', 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000005', 'Specific controls general', 'Rule of construction: a specific call (e.g., a named monument) controls a general call (e.g., a bare bearing/distance) when the two conflict.', 'Monument beats measurement.', 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000006', 'Patent vs. latent ambiguity', 'A patent ambiguity is apparent on the face of the description and may void it; a latent ambiguity appears only when applying the words to the ground and is cured with extrinsic evidence.', NULL, 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000007', 'Patent (Texas)', 'The instrument by which the sovereign (Spain, Mexico, Republic, or State of Texas) first conveyed public land into private ownership; the root of a Texas chain of title.', 'The grant that severs land from the sovereign.', 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000008', 'General Land Office (GLO)', 'The Texas state agency that archives original land-grant records—patents, field notes, and sketches—organized by survey and abstract number.', 'Keeper of original Texas land records.', 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000009', 'Notice recording act', 'Texas''s rule (Prop. Code §13.001) that an unrecorded conveyance is void as to a subsequent bona fide purchaser for value without notice; recording provides constructive notice.', NULL, 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000010', 'Tangent distance (T)', 'For a simple circular curve, T = R·tan(I/2): the distance from the PI to the PC (and from the PI to the PT), measured along the tangents.', 'PC = PI − T.', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000011', 'Arc-length stationing rule', 'Stationing runs continuously along the alignment, so PT = PC + L (the arc length), never PI + T.', 'Walk the curve, not the tangents.', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000012', 'Equal-tangent vertical curve', 'A parabolic curve joining two grades over length L; elevation = Elev_BVC + g1·x + (A/2L)·x² with A = g2 − g1, x and L in stations.', 'High/low point at x = −g1·L/A.', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000013', 'Ground Sample Distance (GSD)', 'The ground distance covered by one image pixel: GSD = (pixel pitch × flight height) / focal length. It sets the effective resolution of aerial/UAS imagery.', 'Fly lower → smaller GSD → more detail.', 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000014', 'Contour interval', 'The constant vertical elevation difference between adjacent contour lines; chosen to match terrain relief and map scale.', 'Close contours = steep ground.', 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000015', 'DTM vs. DSM', 'A Digital Terrain Model (DTM/DEM) represents the bare-earth surface; a Digital Surface Model (DSM) includes vegetation and structures on top of the ground.', NULL, 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000016', 'Standard of care', 'The degree of skill and diligence a reasonably prudent surveyor would exercise under similar circumstances; the yardstick for negligence claims.', 'Reasonably prudent peer, not perfection.', 'c100001a-0000-0000-0000-00000000001a', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000017', 'Elements of negligence', 'Duty, breach (falling below the standard of care), causation, and damages—all four must be present for a negligence claim to succeed.', 'Duty, breach, causation, damages.', 'c100001a-0000-0000-0000-00000000001a', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000018', 'Certification limits', 'A surveyor may sign and seal only work performed under their responsible supervision and may certify only facts actually determined—not guarantees or facts beyond the survey.', NULL, 'c100001a-0000-0000-0000-00000000001a', 'd9587b1a-eff4-4db8-88be-f3175623aa03', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000019', 'RPLS / SIT / LSLS', 'SIT is the surveyor-in-training intern step; RPLS is the standard Texas license to perform independent boundary surveying; LSLS is an additional credential to survey original state-land boundaries and file field notes in the GLO.', 'Intern → licensed → state-land specialist.', 'c100001a-0000-0000-0000-00000000001a', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000020', 'Accretion vs. avulsion', 'Accretion (and erosion) is gradual, imperceptible change that moves the riparian boundary with the water; avulsion is sudden, perceptible change that does NOT move the boundary—the old line is retained.', 'Slow moves the line; sudden fixes it.', 'c100001a-0000-0000-0000-00000000001a', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000021', 'Gradient boundary', 'The legal boundary along a navigable Texas stream—a mid-bank line defined by the water''s gradient—below which the bed may be State-owned.', NULL, 'c100001a-0000-0000-0000-00000000001a', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000022', 'Combined scale factor (CSF)', 'The product of the grid scale factor and the elevation (sea-level) factor used to convert between ground and grid distances: ground = grid ÷ CSF.', 'Grid scale factor × elevation factor.', 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000023', 'Geoid undulation (N)', 'The separation between the geoid and the reference ellipsoid; used to convert ellipsoidal height to orthometric height via H = h − N. In the U.S. N is typically negative.', 'H = h − N.', 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000024', 'Coordinate inverse', 'Computing the distance and azimuth between two coordinate pairs: distance = hypot(ΔE, ΔN); azimuth = atan2(ΔE, ΔN), normalized to 0–360°.', NULL, 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000025', 'NCEES FS Reference Handbook', 'The only reference allowed during the FS exam; it supplies the equations, constants, and tables. Effective prep means learning where each topic lives in the handbook.', 'Open-handbook, not open-book.', 'c100001a-0000-0000-0000-00000000001a', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000026', 'Two-pass strategy', 'Answer all quick questions on the first pass and flag harder ones, then return to flagged items on a second pass—ensuring no blanks and best use of time.', 'Easy first, hard flagged.', 'c100001a-0000-0000-0000-00000000001a', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee2640-0000-0000-0000-000000000027', 'Trap (distractor) answer', 'An incorrect option engineered from a common error—wrong scale-factor direction, wrong sign, degrees/radians mix-up—designed to catch a careless solver.', NULL, 'c100001a-0000-0000-0000-00000000001a', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', 'surveying', ARRAY['buildout','module-26']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000001', 'When the elements of a deed conflict, which element generally controls under the Texas priority of calls?', 'multiple_choice', '["Natural monuments","Distance","Area or quantity","Course (bearing)"]'::jsonb, 'Natural monuments', 'The priority of calls (Stafford v. King) ranks natural monuments highest, then artificial monuments, adjoinder, course, distance, and finally area/quantity. Monuments control measurements.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000002', 'Two parcels were carved from a common grantor and their record dimensions overlap. Under senior rights, who is entitled to the full record dimensions?', 'multiple_choice', '["The parcel conveyed first (senior)","The parcel conveyed last (junior)","Whichever parcel is larger","They split the overlap equally"]'::jsonb, 'The parcel conveyed first (senior)', 'Senior rights give the earliest conveyance its full record; the junior parcel takes only the remainder, absorbing any shortage in the overlap area.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000003', 'A found original monument''s position can be recovered from accessories and reliable testimony even though the physical mark is gone. This corner is best described as:', 'multiple_choice', '["Obliterated (recovered from evidence)","Lost (restored by proportion)","Senior","Avulsed"]'::jsonb, 'Obliterated (recovered from evidence)', 'An obliterated corner has no mark but can be recovered from acceptable evidence. Only a lost corner—recoverable from no evidence—is restored by proportionate measurement.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000004', 'True or False: A retracing surveyor should compute a mathematically ''better'' line rather than follow the original surveyor''s erroneous footsteps.', 'true_false', '["True","False"]'::jsonb, 'False', 'Retracement honors the original footsteps and the boundary the parties accepted, even if the original work contained errors. The goal is to locate the existing boundary, not create a new one.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'a3c8c160-0a68-4aa4-9155-4ddcd1183a53', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000005', 'In a metes-and-bounds call that recites both a found monument and a bearing/distance that disagree, which controls?', 'multiple_choice', '["The monument call","The bearing","The distance","The recited area"]'::jsonb, 'The monument call', 'Specific calls (monuments) control general calls (bearing/distance). A found, identified monument fixes the location over a mere measurement.', 'easy', 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000006', 'A description is clear on its face but, when applied to the ground, two different monuments fit one call. This is an example of a:', 'multiple_choice', '["Latent ambiguity (cured by extrinsic evidence)","Patent ambiguity (voids the deed)","Senior right","Closure error"]'::jsonb, 'Latent ambiguity (cured by extrinsic evidence)', 'A latent ambiguity is not apparent on the page but emerges when applying the words to the ground; courts admit extrinsic evidence to resolve it. A patent ambiguity is apparent on the face.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000007', 'Which type of legal description identifies a parcel by reference to a recorded subdivision map?', 'multiple_choice', '["Lot-and-block (platted)","Metes-and-bounds","Strip/centerline","PLSS aliquot"]'::jsonb, 'Lot-and-block (platted)', 'A lot-and-block description incorporates a recorded plat by reference (e.g., Lot 7, Block C). The plat supplies dimensions and monuments.', 'easy', 'c100001a-0000-0000-0000-00000000001a', '00e59f6c-81a9-46d7-8e06-9e98efec29a8', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000008', 'Where are the original field notes and patents for a Texas land grant archived?', 'multiple_choice', '["The General Land Office (GLO)","The county tax appraisal district","The Bureau of Land Management","TBPELS"]'::jsonb, 'The General Land Office (GLO)', 'The GLO is the archive of original Texas land-grant records—patents, field notes, and sketches—organized by survey and abstract. Subsequent deeds are recorded at the county clerk.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000009', 'Texas is which type of recording-act jurisdiction?', 'multiple_choice', '["Notice","Race","Race-notice","No recording protection"]'::jsonb, 'Notice', 'Under Prop. Code §13.001, Texas is a notice state: an unrecorded conveyance is void as to a subsequent bona fide purchaser for value without notice.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000010', 'True or False: Most original Texas land titles trace to the federal Public Land Survey System (PLSS) of townships and ranges.', 'true_false', '["True","False"]'::jsonb, 'False', 'Texas retained its public domain and uses sovereign grants/patents archived at the GLO, organized by surveys and abstracts—not the federal PLSS.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'c3bca439-c78e-42ce-9416-f7313d08680e', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000011', 'A simple circular curve has R = 500 ft and I = 30°. What is the tangent distance T?', 'numeric_input', '[]'::jsonb, '133.97', 'T = R·tan(I/2) = 500·tan(15°) = 500·0.26795 = 133.97 ft.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000012', 'On a simple curve, the station of the PT is computed as:', 'multiple_choice', '["Sta PC + L","Sta PI + T","Sta PC + 2T","Sta PI + L"]'::jsonb, 'Sta PC + L', 'Stationing runs along the arc, so PT = PC + L. Using PI + T overstates the alignment because the arc is shorter than going out to the PI and back.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000013', 'Which field stake marks the catch point where a designed cut or fill slope intersects existing ground?', 'multiple_choice', '["Slope stake","Offset stake","Grade stake","Centerline hub"]'::jsonb, 'Slope stake', 'A slope stake locates the catch point of the design slope on existing ground, set by trial. Grade and offset stakes carry cut/fill to design grade at or beside the centerline.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '6c0db991-2c1f-469c-83d2-4c3eb7f8f5de', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000014', 'A UAS camera has a pixel pitch of 0.0035 mm and a 35 mm focal length, flying at 120 m AGL. What is the GSD (cm/pixel)?', 'numeric_input', '[]'::jsonb, '1.2', 'GSD = (p·H)/f = (0.0035 mm × 120000 mm)/35 mm = 12 mm = 1.2 cm/pixel.', 'hard', 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000015', 'Which statement about contour lines is correct?', 'multiple_choice', '["Closely spaced contours indicate steep terrain","Contours may cross one another on steep slopes","A single contour can represent two different elevations","Contours always point downhill when crossing a stream"]'::jsonb, 'Closely spaced contours indicate steep terrain', 'Spacing encodes slope—close contours are steep. Contours never cross or branch, each has a single elevation, and they V upstream (toward higher ground) when crossing a drainage.', 'easy', 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000016', 'What does a Digital Terrain Model (DTM/DEM) represent, as opposed to a DSM?', 'multiple_choice', '["The bare-earth surface","The surface including vegetation and buildings","Only the tops of buildings","A 2D planimetric map with no elevations"]'::jsonb, 'The bare-earth surface', 'A DTM/DEM is bare earth; a DSM includes vegetation and structures on top of the ground. Breaklines force the surface to honor grade breaks.', 'easy', 'c100001a-0000-0000-0000-00000000001a', '3a122889-17da-40cf-bf70-4e9fca9f0f31', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000017', 'The legal yardstick used to judge whether a surveyor was negligent is the:', 'multiple_choice', '["Standard of care of a reasonably prudent surveyor","Perfection standard with zero tolerance for error","Client''s subjective satisfaction","Lowest-cost method available"]'::jsonb, 'Standard of care of a reasonably prudent surveyor', 'Negligence is measured against the skill and diligence a reasonably prudent surveyor would exercise under similar circumstances—not perfection or client satisfaction.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'd9587b1a-eff4-4db8-88be-f3175623aa03', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000018', 'Which is NOT one of the four elements required to prove negligence?', 'multiple_choice', '["Intent to harm","Duty","Breach","Damages"]'::jsonb, 'Intent to harm', 'Negligence requires duty, breach, causation, and damages. Intent to harm is not an element—negligence is about failing the standard of care, not intentional wrongdoing.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'd9587b1a-eff4-4db8-88be-f3175623aa03', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000019', 'A river bordering a tract shifts suddenly during a flood, cutting a new channel overnight. Under boundary law, the riparian boundary:', 'multiple_choice', '["Does not move (avulsion retains the old line)","Moves to the new channel (accretion)","Moves to the midpoint of the old and new channels","Is extinguished entirely"]'::jsonb, 'Does not move (avulsion retains the old line)', 'A sudden, perceptible change is avulsion, which does NOT move the boundary—the old line is retained. Only slow, imperceptible accretion/erosion moves the boundary with the water.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000020', 'Which credential is required to survey original state-land grant boundaries and file field notes in the GLO?', 'multiple_choice', '["LSLS (Licensed State Land Surveyor)","SIT (Surveyor-in-Training)","RPLS only","PE (Professional Engineer)"]'::jsonb, 'LSLS (Licensed State Land Surveyor)', 'The LSLS is the additional credential needed to survey original state-land boundaries and file field notes with the GLO; an RPLS alone is not sufficient for original state-land work.', 'medium', 'c100001a-0000-0000-0000-00000000001a', 'beb9522e-1bab-425c-9d43-4c4d0696d9d3', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000021', 'A grid distance is 2000.00 ft and the combined scale factor is 0.9998. What is the corresponding ground distance (ft)?', 'numeric_input', '[]'::jsonb, '2000.40', 'Ground = grid ÷ CSF = 2000.00 / 0.9998 = 2000.40 ft. Ground is longer than grid because CSF < 1.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000022', 'A GNSS observation gives an ellipsoidal height h = 312.40 m at a point where the geoid undulation N = −25.60 m. What is the orthometric height H (m)?', 'numeric_input', '[]'::jsonb, '338.00', 'H = h − N = 312.40 − (−25.60) = 338.00 m. Subtracting a negative N increases H.', 'medium', 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000023', 'Given point A (N 5000.00, E 4000.00) and point B (N 5300.00, E 4400.00), what is the inverse distance A→B (ft)?', 'numeric_input', '[]'::jsonb, '500.00', 'distance = hypot(ΔE, ΔN) = sqrt(400² + 300²) = sqrt(250000) = 500.00 ft (a 3-4-5 triangle).', 'easy', 'c100001a-0000-0000-0000-00000000001a', '7487b90f-db5e-4144-ae61-de244ccc6ef1', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000024', 'Which exam strategy best uses the supplied reference handbook on the FS exam?', 'multiple_choice', '["Learn where each formula and table lives so you can find it quickly","Memorize the entire handbook word for word","Bring your own annotated copy to the test center","Avoid the handbook and rely on memory only"]'::jsonb, 'Learn where each formula and table lives so you can find it quickly', 'The FS exam allows only the supplied handbook. The highest-leverage prep is mastering its layout so you can locate equations and constants in seconds under time pressure.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee2630-0000-0000-0000-000000000025', 'True or False: Because there is no penalty for guessing on the FS exam, you should never leave a question blank.', 'true_false', '["True","False"]'::jsonb, 'True', 'There is no penalty for guessing, so every question should receive an answer. The two-pass strategy ensures flagged questions still get a marked answer before time expires.', 'easy', 'c100001a-0000-0000-0000-00000000001a', 'cc4a39c2-d573-4a23-be15-0b43ebd31774', ARRAY['buildout','module-26']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
