INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000001', 'A line measures {{grid:f2}} ft on the state plane grid. The grid scale factor is {{k:f6}} and the elevation (sea-level) factor is {{ef:f6}}. Using the combined scale factor, what is the ground distance (ft)?', 'numeric_input', '[]'::jsonb, '0', 'Ground distance = grid ÷ CSF, where CSF = {{k:f6}} × {{ef:f6}} = {{csf:f6}}. So {{grid:f2}} ÷ {{csf:f6}} = {{_answer}} ft. Because CSF < 1, the ground distance is slightly longer than the grid distance.', 'medium', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000002', 'A GNSS observation gives an ellipsoidal height of {{h:f2}} m. The geoid model reports a geoid undulation of {{N:f2}} m at the point. What is the orthometric height H (m)?', 'numeric_input', '[]'::jsonb, '0', 'Orthometric height H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} m. Because N is negative here, subtracting it increases H.', 'easy', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000002', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000003', 'A simple circular curve has a radius of {{R}} ft and an intersection angle I = {{I:f2}}°. What is the tangent distance T (ft)?', 'numeric_input', '[]'::jsonb, '0', 'T = R·tan(I/2) = {{R}} × tan({{I:f2}}°/2) = {{_answer}} ft. The PC lies T feet back from the PI along the back tangent.', 'medium', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000003', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000004', 'A simple circular curve has a radius of {{R}} ft and an intersection angle I = {{I:f2}}°. What is the arc length L (ft)?', 'numeric_input', '[]'::jsonb, '0', 'Arc length L = R·I in radians = {{R}} × toRad({{I:f2}}°) = {{_answer}} ft. Station PT = PC + L (along the arc, not PI + T).', 'medium', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000004', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000005', 'A UAS camera has a pixel pitch of {{p:f4}} mm and a focal length of {{f:f1}} mm, flying at {{H}} m above ground level. What is the Ground Sample Distance (cm/pixel)?', 'numeric_input', '[]'::jsonb, '0', 'GSD = (p × H) / f = ({{p:f4}} mm × {{Hmm}} mm) ÷ {{f:f1}} mm = {{gsdmm:f2}} mm = {{_answer}} cm/pixel. Lower flight height gives a smaller (finer) GSD.', 'hard', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000005', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000006', 'Point A is at (N {{n1:f2}}, E {{e1:f2}}) and point B is at (N {{n2:f2}}, E {{e2:f2}}). What is the horizontal distance from A to B (ft)?', 'numeric_input', '[]'::jsonb, '0', 'The inverse distance = hypot(ΔE, ΔN) = sqrt({{de:f2}}² + {{dn:f2}}²) = {{_answer}} ft. Azimuth would be atan2(ΔE, ΔN), normalized to 0–360°.', 'easy', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000006', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2660-0000-0000-0000-000000000007', 'An equal-tangent vertical curve of length {{L}} stations joins an incoming grade g1 = {{g1:f2}}% to an outgoing grade g2 = {{g2:f2}}%. The BVC elevation is {{ebvc:f2}} ft. What is the curve elevation {{x:f2}} stations past the BVC (ft)?', 'numeric_input', '[]'::jsonb, '0', 'On an equal-tangent vertical curve, elevation = Ebvc + g1·x + (A/2L)·x² with A = g2 − g1 = {{A:f2}}%, x and L in stations. Result = {{_answer}} ft.', 'hard', 'c100001a-0000-0000-0000-00000000001a', NULL, ARRAY['buildout','module-26','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2650-0000-0000-0000-000000000007', 0.05);
